sql:
SELECT name, description
FROM neighborhoods
ORDER BY zip_code ASC;

SELECT demographics.crim, employment.avg_annual_salary
FROM demographics
JOIN employment ON demographics.neighborhood_id = employment.neighborhood_id;

SELECT n.name, cr.crime_rate AS highest_crime_rate
FROM neighborhoods n
JOIN crime_rates cr ON n.neighborhood_id = cr.neighborhood_id
WHERE cr.crime_rate = (
    SELECT MAX(crime_rate) FROM crime_rates
);

external_knowledge:
- "stormy seas of high unemployment" metaphorically refers to neighborhoods with high unemployment rates;
- "waves crash with crime rates above the 500 mark" refers to a crime rate above 500 per 1000 residents;
- "troubled neighborhoods" are those facing significant social and economic challenges;
- "waves of crime" metaphorically represents the crime rate;
- "values of their golden houses" refers to the median house prices in thousands;
- "harbingers of these storms" refers to the users who reported these conditions.

sql:
SELECT neighborhoods.name, housing_prices.medv
FROM neighborhoods
INNER JOIN housing_prices ON neighborhoods.neighborhood_id = housing_prices.neighborhood_id;

